FIELDS = [
    "Objective", "Allowed Sources", "Exclusions",
    "Output Artifact", "Decision Rules",
    "Review Checkpoints", "Stop Conditions"
]

def score_brief(brief: dict) -> dict:
    present, specific = [], []
    for field in FIELDS:
        val = brief.get(field, "").strip()
        if val:
            present.append(field)
            if len(val) > 20 and val.lower() not in ("tbd", "n/a", "use judgment"):
                specific.append(field)
    missing = [f for f in FIELDS if f not in present]
    completeness = len(present) / len(FIELDS)
    specificity = len(specific) / max(len(present), 1)
    rating = "READY" if completeness == 1.0 and specificity >= 0.8 else "NOT READY"
    return {"completeness": f"{completeness:.0%}", "specificity": f"{specificity:.0%}",
            "missing": missing, "rating": rating}
